def merge_daily(prism, comm):
    m = {}
    for dt,gmv,gp,qty in prism: m[dt] = {"dt":dt,"gmv":gmv,"gp":gp,"qty":qty,"imp":0,"pdp":0,"purchase":0}
    for dt,imp,pdp,purchase in comm:
        if dt not in m: m[dt] = {"dt":dt,"gmv":0,"gp":0,"qty":0}
        m[dt]["imp"]=imp; m[dt]["pdp"]=pdp; m[dt]["purchase"]=purchase
    return sorted(m.values(), key=lambda r:r["dt"])

